mapper.sql:
from t1_v_dossier_instance_manage

    deleted_at is null

        and model_id = #{modelId}


        and tail_number like concat('%', #{tailNumber}, '%')


        and template_id = #{templateId}


        and current_version_label = #{versionNo}


        and instance_status = #{status}


        and generation_job_status = 'failed'


        and generate_time >= #{beginTime}


        and generate_time <= #{endTime}


        and (
            instance_code like concat('%', #{keyword}, '%')
            or instance_name like concat('%', #{keyword}, '%')
            or instance_label like concat('%', #{keyword}, '%')
            or tail_number like concat('%', #{keyword}, '%')
            or msn like concat('%', #{keyword}, '%')
            or template_name like concat('%', #{keyword}, '%')
            or generation_job_code like concat('%', #{keyword}, '%')
            or pdf_file_name like concat('%', #{keyword}, '%')
            or zip_file_name like concat('%', #{keyword}, '%')
        )

mapper.select:
select


order by generate_time ${sortOrder}, updated_at ${sortOrder}, instance_code desc
limit #{offset}, #{pageSize}

select ej.id as exportJobId, ej.export_code as exportCode, ej.export_status as exportStatus, ej.dossier_instance_id as instanceId, ej.dossier_version_id as versionId, ej.generation_job_id as generationJobId, ef.id as fileId, ef.file_name as fileName, ef.file_storage_key as fileStorageKey, ef.file_format as fileFormat, ef.mime_type as mimeType, ef.file_role as fileRole, ef.is_primary as isPrimary, ef.file_size as fileSize, ef.page_count as pageCount, ef.file_hash as fileHash, ef.display_order as displayOrder, ef.created_at as createdAt from t1_dossier_export_job ej inner join t1_dossier_export_file ef on ef.export_job_id = ej.id where ej.dossier_instance_id = #{instanceId}
and ej.dossier_version_id = #{versionId}
order by ef.display_order, ef.created_at desc
